arguments.cmd:
cat > /tmp/tm_scan.pl <<'PL'
use strict; use warnings;
my %seq;
my $h='';
open my $fh,'<','/app/sequences.fasta' or die $!;
while(<$fh>){chomp; if(/^>(\S+)/){$h=lc($1); next;} $seq{$h}.=lc($_);}
sub rc{my($s)=@_; $s=reverse $s; $s=~tr/acgt/tgca/; return $s;}
my %cfg=(
  input=>{f_start=>693, r_end=>213},
  egfp=>{f_start=>8, r_end=>712},
  flag=>{f_start=>6, r_end=>84},
  snap=>{f_start=>5, r_end=>547},
);
for my $k (qw/input egfp flag snap/){
  my $s=$seq{$k};
  print "== $k ==\n";
  print "FWD\n";
  for my $L (15..36){
    my $sub=substr($s,$cfg{$k}{f_start}-1,$L);
    my $tm=`oligotm -tp 1 -sc 1 -mv 50 -dv 2 -n 0.8 -d 500 $sub`;
    chomp $tm;
    printf "%2d %s %.2f\n",$L,$sub,$tm;
  }
  print "REV\n";
  for my $L (15..36){
    my $st=$cfg{$k}{r_end}-$L+1;
    my $tmpl=substr($s,$st-1,$L);
    my $pr=rc($tmpl);
    my $tm=`oligotm -tp 1 -sc 1 -mv 50 -dv 2 -n 0.8 -d 500 $pr`;
    chomp $tm;
    printf "%2d %s %.2f\n",$L,$pr,$tm;
  }
}
PL
perl /tmp/tm_scan.pl

