cat > /tmp/check_design.pl <<'PL'
use strict;use warnings;
my %s; my $h='';
open my $fh,'<','/app/sequences.fasta' or die $!;
while(<$fh>){chomp; if(/^>(\S+)/){$h=lc($1);next;} $s{$h}.=lc($_);} 
my $out=$s{output};
my %j=(J1=>'gagc',J2=>'aggt',J3=>'agac',J4=>'aatg');
my $core_input = substr($out,1557-1,3591-1557+1) . substr($out,1-1,213);
my $core_egfp  = substr($out,218-1,922-218+1);
my $core_flag  = substr($out,927-1,1005-927+1);
my $core_snap  = substr($out,1010-1,1552-1010+1);
my $recon = $core_input.$j{J1}.$core_egfp.$j{J2}.$core_flag.$j{J3}.$core_snap.$j{J4};
print "recon len ",length($recon)," output len ",length($out)," equal? ",($recon eq $out?'yes':'no'),"\n";
# map cores to templates
sub rc{my($x)=@_;$x=reverse $x;$x=~tr/acgt/tgca/;return $x;}
my $cin = substr($s{input},693-1) . substr($s{input},0,213);
print "input core matches template circular? ",($cin eq $core_input?'yes':'no'),"\n";
print "egfp core matches? ",(substr($s{egfp},8-1,712-8+1) eq $core_egfp?'yes':'no'),"\n";
print "flag core matches? ",(substr($s{flag},6-1,84-6+1) eq $core_flag?'yes':'no'),"\n";
print "snap core matches? ",(substr($s{snap},5-1,547-5+1) eq $core_snap?'yes':'no'),"\n";
PL
perl /tmp/check_design.pl

