cat > /tmp/check_primers.pl <<'PL'
use strict;use warnings;
my %s;my $h='';
open my $fh,'<','/app/sequences.fasta' or die $!;
while(<$fh>){chomp; if(/^>(\S+)/){$h=lc($1);next;} $s{$h}.=lc($_);} 
sub rc{my($x)=@_;$x=reverse $x;$x=~tr/acgt/tgca/;return $x;}
my %cfg=(
 input=>{f_start=>693,f_len=>18,r_end=>213,r_len=>31,jL=>'aatg',jR=>'agca'},
 egfp=>{f_start=>8,f_len=>19,r_end=>712,r_len=>19,jL=>'agca',jR=>'aagg'},
 flag=>{f_start=>6,f_len=>20,r_end=>84,r_len=>22,jL=>'aagg',jR=>'tcag'},
 snap=>{f_start=>5,f_len=>22,r_end=>547,r_len=>19,jL=>'tcag',jR=>'aatg'},
);
for my $k (qw/input egfp flag snap/){
  my $f_anneal=substr($s{$k},$cfg{$k}{f_start}-1,$cfg{$k}{f_len});
  my $r_tmpl=substr($s{$k},$cfg{$k}{r_end}-$cfg{$k}{r_len},$cfg{$k}{r_len});
  my $r_anneal=rc($r_tmpl);
  my $tmf=`oligotm -tp 1 -sc 1 -mv 50 -dv 2 -n 0.8 -d 500 $f_anneal`; chomp $tmf;
  my $tmr=`oligotm -tp 1 -sc 1 -mv 50 -dv 2 -n 0.8 -d 500 $r_anneal`; chomp $tmr;
  printf "%s\tf_anneal=%s\tr_anneal=%s\tf_len=%d\tr_len=%d\tf_tm=%.2f\tr_tm=%.2f\tdelta=%.2f\n",
    $k,$f_anneal,$r_anneal,length($f_anneal),length($r_anneal),$tmf,$tmr,abs($tmf-$tmr);
}
PL
perl /tmp/check_primers.pl

